async function createSessionToken(userId, role, secret) {
  const payload = {
    userId,
    role,
    iat: Date.now(),
    exp: Date.now() + 30 * 24 * 60 * 60 * 1e3
    // 30 days
  };
  const data = btoa(JSON.stringify(payload));
  const sig = await hmacSign(data, secret);
  return `${data}.${sig}`;
}
